import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import AdminLayout from '../components/admin/AdminLayout';
import authService from '../services/authService';
import cmsService from '../services/cmsService';

export default function AdminDashboard() {
  const navigate = useNavigate();
  const [pages, setPages] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [selectedPage, setSelectedPage] = useState(null);
  const [sections, setSections] = useState([]);
  const [showPageModal, setShowPageModal] = useState(false);
  const [showSectionModal, setShowSectionModal] = useState(false);
  const [showCardModal, setShowCardModal] = useState(false);
  const [editingPage, setEditingPage] = useState(null);
  const [editingSection, setEditingSection] = useState(null);
  const [editingCard, setEditingCard] = useState(null);
  const [pageForm, setPageForm] = useState({ slug: '', title: '', metaDescription: '', isPublished: false });
  const [sectionForm, setSectionForm] = useState({ type: 'default', title: '', content: '', image: '', position: 0, isEnabled: true });
  const [cardForm, setCardForm] = useState({ title: '', description: '', icon: '', image: '', position: 0, isEnabled: true });

  useEffect(() => {
    if (!authService.isAdmin()) {
      navigate('/login');
      return;
    }
    fetchPages();
  }, []);

  const fetchPages = async () => {
    try {
      setLoading(true);
      const data = await cmsService.getPages();
      setPages(data);
      setError(null);
    } catch (err) {
      console.log('CMS Tables not available yet');
      setPages([]);
      setError(null);
    } finally {
      setLoading(false);
    }
  };

  const fetchSections = async (pageId) => {
    try {
      const data = await cmsService.getPageWithSections(pageId);
      setSections(data.sections || []);
    } catch (err) {
      console.error('Error fetching sections:', err);
    }
  };

  const handleSelectPage = async (page) => {
    setSelectedPage(page);
    await fetchSections(page.id);
  };

  const handleCreatePage = () => {
    setEditingPage(null);
    setPageForm({ slug: '', title: '', metaDescription: '', isPublished: false });
    setShowPageModal(true);
  };

  const handleEditPage = (page) => {
    setEditingPage(page);
    setPageForm({
      slug: page.slug || '',
      title: page.title || '',
      metaDescription: page.metaDescription || '',
      isPublished: page.isPublished || false
    });
    setShowPageModal(true);
  };

  const handleSavePage = async (e) => {
    e.preventDefault();
    try {
      if (editingPage) {
        await cmsService.updatePage(editingPage.id, pageForm);
      } else {
        await cmsService.createPage(pageForm);
      }
      setShowPageModal(false);
      fetchPages();
    } catch (err) {
      alert(err.message || 'Erreur lors de la sauvegarde');
    }
  };

  const handleDeletePage = async (pageId) => {
    if (!window.confirm('Êtes-vous sûr de vouloir supprimer cette page ?')) return;
    try {
      await cmsService.deletePage(pageId);
      setSelectedPage(null);
      setSections([]);
      fetchPages();
    } catch (err) {
      alert(err.message || 'Erreur lors de la suppression');
    }
  };

  const handleCreateSection = () => {
    setEditingSection(null);
    setSectionForm({ type: 'default', title: '', content: '', image: '', position: sections.length, isEnabled: true });
    setShowSectionModal(true);
  };

  const handleEditSection = (section) => {
    setEditingSection(section);
    setSectionForm({
      type: section.type || 'default',
      title: section.title || '',
      content: section.content || '',
      image: section.image || '',
      position: section.position || 0,
      isEnabled: section.isEnabled ?? true
    });
    setShowSectionModal(true);
  };

  const handleSaveSection = async (e) => {
    e.preventDefault();
    try {
      if (editingSection) {
        await cmsService.updateSection(editingSection.id, sectionForm);
      } else {
        await cmsService.createSection(selectedPage.id, sectionForm);
      }
      setShowSectionModal(false);
      fetchSections(selectedPage.id);
    } catch (err) {
      alert(err.message || 'Erreur lors de la sauvegarde');
    }
  };

  const handleDeleteSection = async (sectionId) => {
    if (!window.confirm('Êtes-vous sûr de vouloir supprimer cette section ?')) return;
    try {
      await cmsService.deleteSection(sectionId);
      fetchSections(selectedPage.id);
    } catch (err) {
      alert(err.message || 'Erreur lors de la suppression');
    }
  };

  const handleCreateCard = (sectionId) => {
    setEditingCard({ sectionId });
    setCardForm({ title: '', description: '', icon: '', image: '', position: 0, isEnabled: true });
    setShowCardModal(true);
  };

  const handleEditCard = (card) => {
    setEditingCard(card);
    setCardForm({
      title: card.title || '',
      description: card.description || '',
      icon: card.icon || '',
      image: card.image || '',
      position: card.position || 0,
      isEnabled: card.isEnabled ?? true
    });
    setShowCardModal(true);
  };

  const handleSaveCard = async (e) => {
    e.preventDefault();
    try {
      if (editingCard?.id) {
        await cmsService.updateCard(editingCard.id, cardForm);
      } else {
        await cmsService.createCard(editingCard.sectionId, cardForm);
      }
      setShowCardModal(false);
      fetchSections(selectedPage.id);
    } catch (err) {
      alert(err.message || 'Erreur lors de la sauvegarde');
    }
  };

  const handleDeleteCard = async (cardId) => {
    if (!window.confirm('Êtes-vous sûr de vouloir supprimer cette carte ?')) return;
    try {
      await cmsService.deleteCard(cardId);
      fetchSections(selectedPage.id);
    } catch (err) {
      alert(err.message || 'Erreur lors de la suppression');
    }
  };

  const getSectionIcon = (type) => {
    switch (type) {
      case 'hero': return 'fa-bolt';
      case 'features': return 'fa-star';
      case 'benefits': return 'fa-handshake';
      case 'pricing': return 'fa-tag';
      case 'steps': return 'fa-list-ol';
      case 'faq': return 'fa-question-circle';
      case 'cta': return 'fa-bullhorn';
      default: return 'fa-th-large';
    }
  };

  return (
    <AdminLayout>
      <div>
        {/* Page Header */}
        <div className="mb-8 flex items-center justify-between">
          <div>
            <h1 className="text-2xl font-bold text-gray-900">Gestion du Site Web</h1>
            <p className="text-gray-600 mt-1">
              Gérez le contenu de votre site directement depuis ici
            </p>
          </div>
          <button
            onClick={handleCreatePage}
            className="bg-yellow-500 text-white px-4 py-2 rounded-lg hover:bg-yellow-600 flex items-center gap-2"
          >
            <i className="fas fa-plus"></i>
            Nouvelle Page
          </button>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Pages List */}
          <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
            <div className="p-4 border-b border-gray-100 bg-yellow-50">
              <h2 className="font-semibold text-gray-900 flex items-center gap-2">
                <i className="fas fa-file-alt text-yellow-600"></i>
                Pages du Site
              </h2>
            </div>

            {loading ? (
              <div className="p-8 text-center">
                <i className="fas fa-spinner fa-spin text-2xl text-yellow-500"></i>
              </div>
            ) : error ? (
              <div className="p-8 text-center">
                <p className="text-red-500">{error}</p>
                <button onClick={fetchPages} className="mt-2 text-yellow-600">Réessayer</button>
              </div>
            ) : pages.length === 0 ? (
              <div className="p-8 text-center">
                <i className="fas fa-file-alt text-4xl text-gray-300"></i>
                <p className="mt-2 text-gray-500">Aucune page</p>
                <button onClick={handleCreatePage} className="mt-2 text-yellow-600">Créer une page</button>
              </div>
            ) : (
              <div className="divide-y divide-gray-100 max-h-[600px] overflow-y-auto">
                {pages.map((page) => (
                  <div
                    key={page.id}
                    onClick={() => handleSelectPage(page)}
                    className={`p-4 cursor-pointer hover:bg-gray-50 transition-colors ${
                      selectedPage?.id === page.id ? 'bg-yellow-50 border-l-4 border-yellow-500' : ''
                    }`}
                  >
                    <div className="flex items-center justify-between">
                      <div>
                        <h3 className="font-medium text-gray-900">{page.title}</h3>
                        <p className="text-sm text-gray-500">/{page.slug}</p>
                      </div>
                      <div className="flex items-center gap-2">
                        <span className={`px-2 py-1 text-xs rounded-full ${
                          page.isPublished ? 'bg-green-100 text-green-600' : 'bg-gray-100 text-gray-600'
                        }`}>
                          {page.isPublished ? 'Publié' : 'Brouillon'}
                        </span>
                        <button
                          onClick={(e) => { e.stopPropagation(); handleEditPage(page); }}
                          className="text-blue-600 hover:text-blue-800 p-1"
                        >
                          <i className="fas fa-edit"></i>
                        </button>
                        <button
                          onClick={(e) => { e.stopPropagation(); handleDeletePage(page.id); }}
                          className="text-red-600 hover:text-red-800 p-1"
                        >
                          <i className="fas fa-trash"></i>
                        </button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Sections Panel */}
          <div className="lg:col-span-2 bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
            {selectedPage ? (
              <>
                <div className="p-4 border-b border-gray-100 bg-yellow-50 flex items-center justify-between">
                  <div>
                    <h2 className="font-semibold text-gray-900 flex items-center gap-2">
                      <i className="fas fa-layer-group text-yellow-600"></i>
                      Sections: {selectedPage.title}
                    </h2>
                    <p className="text-sm text-gray-500">/{selectedPage.slug}</p>
                  </div>
                  <button
                    onClick={handleCreateSection}
                    className="bg-yellow-500 text-white px-3 py-2 rounded-lg hover:bg-yellow-600 text-sm flex items-center gap-2"
                  >
                    <i className="fas fa-plus"></i>
                    Ajouter Section
                  </button>
                </div>

                {sections.length === 0 ? (
                  <div className="p-8 text-center">
                    <i className="fas fa-th-large text-4xl text-gray-300"></i>
                    <p className="mt-2 text-gray-500">Aucune section</p>
                    <button onClick={handleCreateSection} className="mt-2 text-yellow-600">Ajouter une section</button>
                  </div>
                ) : (
                  <div className="divide-y divide-gray-100 max-h-[600px] overflow-y-auto">
                    {sections.map((section) => (
                      <div key={section.id} className="p-4 hover:bg-gray-50">
                        <div className="flex items-start justify-between">
                          <div className="flex items-start gap-3">
                            <div className="w-10 h-10 bg-yellow-100 rounded-lg flex items-center justify-center flex-shrink-0">
                              <i className={`fas ${getSectionIcon(section.type)} text-yellow-600`}></i>
                            </div>
                            <div>
                              <h3 className="font-medium text-gray-900">{section.title || 'Section sans titre'}</h3>
                              <p className="text-sm text-gray-500 capitalize">{section.type || 'default'}</p>
                              {section.content && (
                                <p className="text-sm text-gray-600 mt-1 line-clamp-2">{section.content.substring(0, 100)}...</p>
                              )}
                              {section.cards && section.cards.length > 0 && (
                                <div className="mt-2 flex flex-wrap gap-2">
                                  {section.cards.map((card) => (
                                    <span key={card.id} className="text-xs bg-gray-100 px-2 py-1 rounded">
                                      {card.title}
                                    </span>
                                  ))}
                                </div>
                              )}
                            </div>
                          </div>
                          <div className="flex items-center gap-2">
                            <button
                              onClick={() => handleEditSection(section)}
                              className="text-blue-600 hover:text-blue-800 p-2"
                            >
                              <i className="fas fa-edit"></i>
                            </button>
                            <button
                              onClick={() => handleDeleteSection(section.id)}
                              className="text-red-600 hover:text-red-800 p-2"
                            >
                              <i className="fas fa-trash"></i>
                            </button>
                          </div>
                        </div>

                        {/* Cards Management */}
                        <div className="mt-4 pl-13">
                          <div className="flex items-center justify-between mb-2">
                            <span className="text-sm font-medium text-gray-700">Cartes/Éléments</span>
                            <button
                              onClick={() => handleCreateCard(section.id)}
                              className="text-xs text-yellow-600 hover:text-yellow-800"
                            >
                              <i className="fas fa-plus mr-1"></i>Ajouter carte
                            </button>
                          </div>
                          <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
                            {section.cards?.map((card) => (
                              <div key={card.id} className="bg-gray-50 rounded-lg p-3 flex items-center justify-between">
                                <div className="flex items-center gap-2">
                                  {card.icon && <i className={`fas ${card.icon} text-yellow-500`}></i>}
                                  <span className="text-sm">{card.title}</span>
                                </div>
                                <div className="flex gap-1">
                                  <button onClick={() => handleEditCard(card)} className="text-blue-600 hover:text-blue-800">
                                    <i className="fas fa-edit text-xs"></i>
                                  </button>
                                  <button onClick={() => handleDeleteCard(card.id)} className="text-red-600 hover:text-red-800">
                                    <i className="fas fa-trash text-xs"></i>
                                  </button>
                                </div>
                              </div>
                            ))}
                            {(!section.cards || section.cards.length === 0) && (
                              <p className="text-xs text-gray-400 col-span-2">Aucune carte</p>
                            )}
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </>
            ) : (
              <div className="p-8 text-center">
                <i className="fas fa-hand-pointer text-4xl text-gray-300"></i>
                <p className="mt-2 text-gray-500">Sélectionnez une page pour voir ses sections</p>
              </div>
            )}
          </div>
        </div>

        {/* Page Modal */}
        {showPageModal && (
          <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
            <div className="bg-white rounded-xl p-6 w-full max-w-md mx-4">
              <h2 className="text-xl font-bold text-gray-900 mb-4">
                {editingPage ? 'Modifier la page' : 'Nouvelle page'}
              </h2>
              <form onSubmit={handleSavePage} className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Titre *</label>
                  <input
                    type="text"
                    value={pageForm.title}
                    onChange={(e) => setPageForm({ ...pageForm, title: e.target.value })}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 outline-none"
                    required
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Slug (URL) *</label>
                  <input
                    type="text"
                    value={pageForm.slug}
                    onChange={(e) => setPageForm({ ...pageForm, slug: e.target.value.toLowerCase().replace(/\s+/g, '-') })}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 outline-none"
                    placeholder="ma-page"
                    required
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Méta description</label>
                  <textarea
                    value={pageForm.metaDescription}
                    onChange={(e) => setPageForm({ ...pageForm, metaDescription: e.target.value })}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 outline-none"
                    rows={3}
                  />
                </div>
                <div className="flex items-center gap-2">
                  <input
                    type="checkbox"
                    id="isPublished"
                    checked={pageForm.isPublished}
                    onChange={(e) => setPageForm({ ...pageForm, isPublished: e.target.checked })}
                    className="w-4 h-4 text-yellow-500 border-gray-300 rounded"
                  />
                  <label htmlFor="isPublished" className="text-sm text-gray-700">Publier la page</label>
                </div>
                <div className="flex gap-2 pt-4">
                  <button type="button" onClick={() => setShowPageModal(false)} className="flex-1 px-4 py-2 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50">
                    Annuler
                  </button>
                  <button type="submit" className="flex-1 px-4 py-2 bg-yellow-500 text-white rounded-lg hover:bg-yellow-600">
                    Sauvegarder
                  </button>
                </div>
              </form>
            </div>
          </div>
        )}

        {/* Section Modal */}
        {showSectionModal && (
          <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
            <div className="bg-white rounded-xl p-6 w-full max-w-lg mx-4 max-h-[90vh] overflow-y-auto">
              <h2 className="text-xl font-bold text-gray-900 mb-4">
                {editingSection ? 'Modifier la section' : 'Nouvelle section'}
              </h2>
              <form onSubmit={handleSaveSection} className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Type de section</label>
                  <select
                    value={sectionForm.type}
                    onChange={(e) => setSectionForm({ ...sectionForm, type: e.target.value })}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ringring-yellow-500 outline-none"
                  >
                    <option value="default">Default</option>
                    <option value="hero">Hero (En-tête)</option>
                    <option value="features">Features (Caractéristiques)</option>
                    <option value="benefits">Benefits (Avantages)</option>
                    <option value="pricing">Pricing (Tarifs)</option>
                    <option value="steps">Steps (Étapes)</option>
                    <option value="faq">FAQ</option>
                    <option value="cta">Call to Action</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Titre</label>
                  <input
                    type="text"
                    value={sectionForm.title}
                    onChange={(e) => setSectionForm({ ...sectionForm, title: e.target.value })}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 outline-none"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Contenu</label>
                  <textarea
                    value={sectionForm.content}
                    onChange={(e) => setSectionForm({ ...sectionForm, content: e.target.value })}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 outline-none"
                    rows={4}
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Image (URL)</label>
                  <input
                    type="text"
                    value={sectionForm.image}
                    onChange={(e) => setSectionForm({ ...sectionForm, image: e.target.value })}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 outline-none"
                    placeholder="https://..."
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Position</label>
                  <input
                    type="number"
                    value={sectionForm.position}
                    onChange={(e) => setSectionForm({ ...sectionForm, position: parseInt(e.target.value) })}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 outline-none"
                  />
                </div>
                <div className="flex items-center gap-2">
                  <input
                    type="checkbox"
                    id="sectionEnabled"
                    checked={sectionForm.isEnabled}
                    onChange={(e) => setSectionForm({ ...sectionForm, isEnabled: e.target.checked })}
                    className="w-4 h-4 text-yellow-500 border-gray-300 rounded"
                  />
                  <label htmlFor="sectionEnabled" className="text-sm text-gray-700">Activer la section</label>
                </div>
                <div className="flex gap-2 pt-4">
                  <button type="button" onClick={() => setShowSectionModal(false)} className="flex-1 px-4 py-2 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50">
                    Annuler
                  </button>
                  <button type="submit" className="flex-1 px-4 py-2 bg-yellow-500 text-white rounded-lg hover:bg-yellow-600">
                    Sauvegarder
                  </button>
                </div>
              </form>
            </div>
          </div>
        )}

        {/* Card Modal */}
        {showCardModal && (
          <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
            <div className="bg-white rounded-xl p-6 w-full max-w-lg mx-4">
              <h2 className="text-xl font-bold text-gray-900 mb-4">
                {editingCard?.id ? 'Modifier la carte' : 'Nouvelle carte'}
              </h2>
              <form onSubmit={handleSaveCard} className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Titre</label>
                  <input
                    type="text"
                    value={cardForm.title}
                    onChange={(e) => setCardForm({ ...cardForm, title: e.target.value })}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 outline-none"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Description</label>
                  <textarea
                    value={cardForm.description}
                    onChange={(e) => setCardForm({ ...cardForm, description: e.target.value })}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 outline-none"
                    rows={3}
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Icône (FontAwesome)</label>
                  <input
                    type="text"
                    value={cardForm.icon}
                    onChange={(e) => setCardForm({ ...cardForm, icon: e.target.value })}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 outline-none"
                    placeholder="fa-star, fa-check, fa-bolt"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Image (URL)</label>
                  <input
                    type="text"
                    value={cardForm.image}
                    onChange={(e) => setCardForm({ ...cardForm, image: e.target.value })}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 outline-none"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Position</label>
                  <input
                    type="number"
                    value={cardForm.position}
                    onChange={(e) => setCardForm({ ...cardForm, position: parseInt(e.target.value) })}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 outline-none"
                  />
                </div>
                <div className="flex items-center gap-2">
                  <input
                    type="checkbox"
                    id="cardEnabled"
                    checked={cardForm.isEnabled}
                    onChange={(e) => setCardForm({ ...cardForm, isEnabled: e.target.checked })}
                    className="w-4 h-4 text-yellow-500 border-gray-300 rounded"
                  />
                  <label htmlFor="cardEnabled" className="text-sm text-gray-700">Activer la carte</label>
                </div>
                <div className="flex gap-2 pt-4">
                  <button type="button" onClick={() => setShowCardModal(false)} className="flex-1 px-4 py-2 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50">
                    Annuler
                  </button>
                  <button type="submit" className="flex-1 px-4 py-2 bg-yellow-500 text-white rounded-lg hover:bg-yellow-600">
                    Sauvegarder
                  </button>
                </div>
              </form>
            </div>
          </div>
        )}
      </div>
    </AdminLayout>
  );
}
